#include <stdio.h>
#include <stdlib.h>

long long power(long long a, long long b, long long m) {
    long long res = 1;
    while (b > 0) {
        if (b & 1)
            res = (res * a) % m;
        a = (a * a) % m;
        b >>= 1;
    }
    return res;
}

long long fun(long long* A, int* S, int len, int N, long long M) {
    if (len == 1)
        return A[S[0]];
    long long res = power(A[S[0]], fun(A, S + 1, len - 1, N, M), M);
    return res;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        long long* A = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; i++)
            scanf("%lld", &A[i]);
        long long sum = 0;
        for (int mask = 1; mask < (1 << N); mask++) {
            int len = 0;
            int* S = (int*)malloc(N * sizeof(int));
            for (int i = 0; i < N; i++) {
                if (mask & (1 << i)) {
                    S[len] = i;
                    len++;
                }
            }
            sum = (sum + fun(A, S, len, N, M)) % M;
            free(S);
        }
        printf("%lld\n", sum);
        free(A);
    }
    return 0;
}

