import java.util.Scanner;
public class Main {
    public static long power(long a, long b, long m) {
        long res = 1;
        while (b > 0) {
            if (b % 2 == 1)
                res = (res * a) % m;
            a = (a * a) % m;
            b >>= 1;
        }
        return res;
    }

    public static long fun(long[] A, int[] S, int len, int N, long M) {
        if (len == 1)
            return A[S[0]];
        long res = power(A[S[0]], fun(A, Arrays.copyOfRange(S, 1, len), len - 1, N, M), M);
        return res;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            long M = sc.nextLong();
            long[] A = new long[N];
            for (int i = 0; i < N; i++)
                A[i] = sc.nextLong();
            long sum = 0;
            for (int mask = 1; mask < (1 << N); mask++) {
                int len = 0;
                int[] S = new int[N];
                for (int i = 0; i < N; i++) {
                    if ((mask & (1 << i)) > 0) {
                        S[len] = i;
                        len++;
                    }
                }
                sum = (sum + fun(A, S, len, N, M)) % M;
            }
            System.out.println(sum);
        }
    }
}

