def power(a, b, m):
    res = 1
    while b > 0:
        if b % 2 == 1:
            res = (res * a) % m
        a = (a * a) % m
        b >>= 1
    return res

def fun(A, S, len, N, M):
    if len == 1:
        return A[S[0]]
    res = power(A[S[0]], fun(A, S[1:], len - 1, N, M), M)
    return res

def main():
    T = int(input())
    for _ in range(T):
        N, M = map(int, input().split())
        A = list(map(int, input().split()))
        sum = 0
        for mask in range(1, 1 << N):
            len = 0
            S = []
            for i in range(N):
                if mask & (1 << i):
                    S.append(i)
                    len += 1
            sum = (sum + fun(A, S, len, N, M)) % M
        print(sum)
main()

